#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int maxA=100000;
        int *freq = (int*)calloc(maxA+1,sizeof(int));
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            freq[x]++;
        }
        long long ans=0;
        for(int v=2; v<=maxA; ++v){
            if(freq[v]){
                int possible=v-1;
                ans+= (freq[v] < possible) ? freq[v] : possible;
            }
        }
        free(freq);
        printf("%lld\n",ans);
    }
    return 0;
}

