#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        unordered_map<int,int> freq;
        freq.reserve(N*2);
        for(int i=0;i<N;++i){
            int x; cin>>x; ++freq[x];
        }
        long long ans=0;
        for(auto &p:freq){
            int val=p.first, cnt=p.second;
            ans+= min(cnt, val-1);
        }
        cout<<ans<<"\n";
    }
    return 0;
}

