import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        freq = {}
        for _ in range(N):
            x = next(it)
            freq[x] = freq.get(x, 0) + 1
        ans = 0
        for val, cnt in freq.items():
            ans += min(cnt, val-1)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

